using System;
using System.Collections.Generic;
using System.Net.WebSockets;
using System.Text;
using System.Threading;
using System.Threading.Tasks;
using System.Web.Script.Serialization;
using GTA;
using GTA.Math;
using GTA.Native;

namespace ModProject
{
    public class Mod : Script
    {
        private const string LiveStudioUrl = "ws://127.0.0.1:60080";
        private const string SubscribeSignal = "serviceSignalSub";
        private const string SubscribeTransport = "IM_MESSAGE_TRANSPORT";
        private const int GiftIdRose = 5655;
        private const int WantedLevelTarget = 3;
        private const int CooldownMs = 30000;

        private ClientWebSocket _webSocket;
        private CancellationTokenSource _cts;
        private readonly Queue<Action> _mainThreadActions = new Queue<Action>();
        private readonly object _queueLock = new object();
        private readonly JavaScriptSerializer _jsonSerializer = new JavaScriptSerializer();
        private DateTime _lastTriggerTime = DateTime.MinValue;
        private bool _isConnected;

        public Mod()
        {
            Tick += OnTick;
            Interval = 100;
            _cts = new CancellationTokenSource();
            Task.Run(() => ConnectAndListen(_cts.Token));
        }

        private void OnTick(object sender, EventArgs e)
        {
            ProcessMainThreadQueue();
            UpdateConnectionStatus();
        }

        private void ProcessMainThreadQueue()
        {
            List<Action> actions = null;
            lock (_queueLock)
            {
                if (_mainThreadActions.Count > 0)
                {
                    actions = new List<Action>(_mainThreadActions);
                    _mainThreadActions.Clear();
                }
            }

            if (actions != null)
            {
                foreach (var action in actions)
                {
                    try
                    {
                        action();
                    }
                    catch (Exception ex)
                    {
                        // 静默处理，避免异常导致 Tick 中断
                    }
                }
            }
        }

        private void UpdateConnectionStatus()
        {
            if (_webSocket == null || (_webSocket.State != WebSocketState.Open && _webSocket.State != WebSocketState.Connecting))
            {
                if (_isConnected)
                {
                    _isConnected = false;
                }
            }
        }

        private async Task ConnectAndListen(CancellationToken ct)
        {
            while (!ct.IsCancellationRequested)
            {
                try
                {
                    using (_webSocket = new ClientWebSocket())
                    {
                        await _webSocket.ConnectAsync(new Uri(LiveStudioUrl), ct);
                        _isConnected = true;

                        // 发送订阅
                        var subscribeMsg = new
                        {
                            type = SubscribeSignal,
                            transport = SubscribeTransport
                        };
                        string subscribeJson = _jsonSerializer.Serialize(subscribeMsg);
                        byte[] subscribeBytes = Encoding.UTF8.GetBytes(subscribeJson);
                        await _webSocket.SendAsync(new ArraySegment<byte>(subscribeBytes), WebSocketMessageType.Text, true, ct);

                        await ReceiveMessages(ct);
                    }
                }
                catch (Exception)
                {
                    _isConnected = false;
                }

                // 重连等待
                try
                {
                    await Task.Delay(5000, ct);
                }
                catch (TaskCanceledException)
                {
                    break;
                }
            }
        }

        private async Task ReceiveMessages(CancellationToken ct)
        {
            var buffer = new byte[4096];
            var messageBuffer = new StringBuilder();

            while (_webSocket.State == WebSocketState.Open && !ct.IsCancellationRequested)
            {
                var result = await _webSocket.ReceiveAsync(new ArraySegment<byte>(buffer), ct);

                if (result.MessageType == WebSocketMessageType.Close)
                {
                    await _webSocket.CloseAsync(WebSocketCloseStatus.NormalClosure, "Closing", CancellationToken.None);
                    break;
                }

                if (result.MessageType == WebSocketMessageType.Text)
                {
                    messageBuffer.Append(Encoding.UTF8.GetString(buffer, 0, result.Count));

                    if (result.EndOfMessage)
                    {
                        string completeMessage = messageBuffer.ToString();
                        messageBuffer.Clear();
                        ProcessIncomingMessage(completeMessage);
                    }
                }
            }
        }

        private void ProcessIncomingMessage(string rawJson)
        {
            try
            {
                var message = _jsonSerializer.Deserialize<Dictionary<string, object>>(rawJson);

                if (message == null)
                    return;

                // 检查是否为礼物消息
                if (message.ContainsKey("gift_id") || message.ContainsKey("giftId"))
                {
                    HandleGiftMessage(message);
                }
            }
            catch (Exception)
            {
                // 解析失败，忽略
            }
        }

        private void HandleGiftMessage(Dictionary<string, object> message)
        {
            // 提取 gift_id
            object giftIdObj = null;
            if (message.ContainsKey("gift_id"))
                giftIdObj = message["gift_id"];
            else if (message.ContainsKey("giftId"))
                giftIdObj = message["giftId"];

            if (giftIdObj == null)
                return;

            int giftId = 0;
            if (giftIdObj is int idInt)
                giftId = idInt;
            else if (giftIdObj is string idStr && int.TryParse(idStr, out int parsedId))
                giftId = parsedId;
            else
                return;

            // 检查是否为玫瑰礼物
            if (giftId != GiftIdRose)
                return;

            // 检查冷却时间
            DateTime now = DateTime.UtcNow;
            if ((now - _lastTriggerTime).TotalMilliseconds < CooldownMs)
                return;

            _lastTriggerTime = now;

            // 将效果执行放入主线程队列
            EnqueueMainThreadAction(() => ExecuteRoseEffects());
        }

        private void EnqueueMainThreadAction(Action action)
        {
            lock (_queueLock)
            {
                // 队列上限保护，防止内存泄漏
                if (_mainThreadActions.Count < 100)
                {
                    _mainThreadActions.Enqueue(action);
                }
            }
        }

        private void ExecuteRoseEffects()
        {
            Ped playerPed = Game.Player.Character;
            if (playerPed == null)
                return;

            try
            {
                // 1. 天气改为下雨
                World.Weather = Weather.Raining;

                // 2. 血量变为一半
                int maxHealth = playerPed.MaxHealth;
                int halfHealth = Math.Max(1, maxHealth / 2);
                playerPed.Health = halfHealth;

                // 3. 三星通缉
                Game.Player.WantedLevel = WantedLevelTarget;

                // 4. 刷新狙击枪
                playerPed.Weapons.Give(WeaponHash.SniperRifle, 30, true, true);
            }
            catch (Exception)
            {
                // 效果执行异常，静默处理
            }
        }

        protected override void Dispose(bool disposing)
        {
            if (disposing)
            {
                _cts?.Cancel();
                _webSocket?.Dispose();
                _cts?.Dispose();
            }
            base.Dispose(disposing);
        }
    }
}
